import json
from html.parser import HTMLParser

# 1. Define the Parser Class
class OnlinerApartmentParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.data = {
            "cover_url": None,
            "address": "",
            "last_update": None,
            "creation_date": None,
            "description": "",
            "price": None,
            "phone": ""
        }

        # Internal state tracking
        self.in_cover = False
        self.in_address = False
        self.in_creation_date = False
        self.in_last_update = False
        self.in_description = False
        self.in_price = False
        self.in_phone_list = False
        self.capture_phone = False
        self.phones_found = []

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        classes = attrs_dict.get('class', '').split()

        # Cover URL
        # Look for <div class="apartment-cover" style="background-image: url(...)">
        if tag == 'div' and 'apartment-cover' in classes:
            style = attrs_dict.get('style', '')
            if 'background-image' in style:
                # Simple extraction of url(...)
                start_marker = 'url('
                start = style.find(start_marker)
                if start != -1:
                    end = style.find(')', start)
                    url_raw = style[start + len(start_marker):end]
                    # Clean up quotes if present
                    self.data['cover_url'] = url_raw.strip('"\'')

        # Address
        # Look for <div class="apartment-info__sub-line apartment-info__sub-line_large">
        if tag == 'div' and 'apartment-info__sub-line_large' in classes:
            self.in_address = True

        # Price
        # Look for <span class="apartment-bar__price-value_primary">
        if tag == 'span' and 'apartment-bar__price-value_primary' in classes:
            self.in_price = True

        # Description
        # Look for <div class="apartment-info__sub-line apartment-info__sub-line_extended-bottom">
        # Note: There might be multiple blocks with this class. The description is usually the first one or distinct by context.
        # Based on the file structure, the description is in the 'apartment-info__cell_66' block inside this specific sub-line class.
        if tag == 'div' and 'apartment-info__sub-line_extended-bottom' in classes:
            # We assume description is empty initially, so capturing the first occurrence is often correct 
            # or we append if broken into tags.
            self.in_description = True

        # Dates: Creation and Update
        # "Размещено X назад" is usually in `apartment-info__sub-line_extended-bottom_condensed`
        # "Последний раз редактировалось" is followed by <span id="apartment-updated-at">
        if tag == 'div' and 'apartment-info__sub-line_extended-bottom_condensed' in classes:
            self.in_creation_date = True # Tentative, check content

        if tag == 'span' and attrs_dict.get('id') == 'apartment-updated-at':
            self.in_last_update = True

        # Phone
        # Inside <ul class="apartment-info__list_phones"> ... <a href="tel:...">
        if tag == 'ul' and 'apartment-info__list_phones' in classes:
            self.in_phone_list = True

        if self.in_phone_list and tag == 'a':
             if 'href' in attrs_dict and attrs_dict['href'].startswith('tel:'):
                 self.capture_phone = True

    def handle_endtag(self, tag):
        if tag == 'div':
            self.in_address = False
            self.in_description = False
            self.in_creation_date = False
            # We don't turn off in_price immediately on div, it's a span usually

        if tag == 'span':
            self.in_price = False
            self.in_last_update = False

        if tag == 'ul' and self.in_phone_list:
            self.in_phone_list = False

        if tag == 'a' and self.capture_phone:
            self.capture_phone = False

    def handle_data(self, data):
        text = data.strip()
        if not text:
            return

        if self.in_address:
            self.data['address'] = text

        if self.in_price:
            self.data['price'] = text

        if self.in_description:
            # If description already has data, append (e.g. <br> tags separation)
            if self.data['description']:
                self.data['description'] += "<br>\n" + text
            else:
                self.data['description'] = text

        if self.in_creation_date:
            if "Размещено" in text:
                self.data['creation_date'] = text.replace("Размещено", "").strip()

        if self.in_last_update:
            self.data['last_update'] = text

        if self.capture_phone:
            self.phones_found.append(text)

    def finalize(self):
        if self.phones_found:
            self.data['phone'] = " ".join(self.phones_found)
        else:
            self.data['phone'] = None


