import json
import re
from html.parser import HTMLParser
from datetime import datetime

class ApartmentParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.apartments = []
        self.current_apartment = {}
        self.in_classified = False
        self.in_link = False
        self.capture_href = False
        self.capture_time = False
        self.current_time_text = ""

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)

        # Check if this is an apartment listing
        if tag == 'a' and 'class' in attrs_dict and 'classified' in attrs_dict['class']:
            self.in_classified = True
            self.in_link = True

            # Extract the link
            if 'href' in attrs_dict:
                self.current_apartment['link'] = attrs_dict['href']

            # Extract the data-id
            if 'data-id' in attrs_dict:
                self.current_apartment['id'] = attrs_dict['data-id']

        # Look for time element in apartment listing
        if self.in_classified and tag == 'span' and 'class' in attrs_dict:
            if 'classified__time' in attrs_dict['class']:
                self.capture_time = True
                self.current_time_text = ""

    def handle_endtag(self, tag):
        if tag == 'a' and self.in_link:
            self.in_link = False
            if self.current_apartment:
                # If we have both link and time, add to list
                if 'link' in self.current_apartment and 'time_text' in self.current_apartment:
                    self.apartments.append(self.current_apartment.copy())
                self.current_apartment = {}

        if tag == 'span' and self.capture_time:
            self.capture_time = False
            if self.current_time_text and self.in_classified:
                self.current_apartment['time_text'] = self.current_time_text.strip()
                self.current_time_text = ""

    def handle_data(self, data):
        if self.capture_time:
            self.current_time_text += data

def extract_apartment_info(html_content):
    """Extract apartment links and update dates from HTML content"""

    # Initialize parser
    parser = ApartmentParser()
    parser.feed(html_content)

    # Process the extracted data
    results = []

    for apt in parser.apartments:
        # Extract and clean time information
        time_text = apt.get('time_text', '')

        # Parse relative time to standardized format
        update_time = parse_relative_time(time_text)

        item_id = apt.get('id')
        if not re.match(r'^\d+$', item_id):
            raise ValueError(f"ID '{item_id}' does not match pattern '^\d+$'")

        apartment_info = {
            'id': apt.get('id'),
            'link': apt.get('link', ''),
            'time_text': time_text,
            'update_time': update_time,
            'host': _items[0]["json"]["host"],
        }

        results.append(apartment_info)

    return results

def parse_relative_time(time_text):
    """Parse relative time strings to standardized format"""

    if not time_text:
        return ""

    time_text = time_text.lower().strip()
    now = datetime.now()
    timezone = 3 * 3600
    #print(now.timestamp())

    # Handle minutes
    if time_text == "минуту назад":
        minutes = 1
        delta = now.timestamp() - (minutes * 60) + timezone
        return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')
    else:
        minutes_match = re.search(r'(\d+)\s*(минут|мин)', time_text)
        if minutes_match:
            minutes = int(minutes_match.group(1))
            delta = now.timestamp() - (minutes * 60) + timezone
            return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')

    # Handle hours
    if time_text == "час назад":
        hours = 1
        delta = now.timestamp() - (hours * 3600) + timezone
        return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')
    else:
        hours_match = re.search(r'(\d+)\s*(час|ч)', time_text)
        if hours_match:
            hours = int(hours_match.group(1))
            delta = now.timestamp() - (hours * 3600) + timezone
            return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')

    # Handle days
    if time_text == "день назад":
        days = 1
        delta = now.timestamp() - (days * 86400) + timezone
        return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')
    else:
        days_match = re.search(r'(\d+)\s*(день|дн|дня|дней)', time_text)
        if days_match:
          days = int(days_match.group(1))
          delta = now.timestamp() - (days * 86400) + timezone
          return datetime.fromtimestamp(delta).strftime('%Y-%m-%d %H:%M:%S')

    # Handle "сегодня" (today)
    if 'сегодня' in time_text:
        return now.strftime('%Y-%m-%d')

    # Handle "вчера" (yesterday)
    if 'вчера' in time_text:
        delta = now.timestamp() - 86400 + timezone
        return datetime.fromtimestamp(delta).strftime('%Y-%m-%d')

    if 'месяц' in time_text:
        delta = now.timestamp() - 86400 * 30 + timezone
        return datetime.fromtimestamp(delta).strftime('%Y-%m-%d')

    # If we can't parse it, return the original text
    return time_text


