apartments = extract_apartment_info(html_content)
output = {
    "source": "https://r.onliner.by/ak/",
    "extraction_date": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
    "total_apartments": len(apartments),
    "apartments": apartments
}

return output

