        self.h1_text = ""

        # Description
        self.in_text_content = False
        self.desc_div_depth = 0
        self.ignore_desc = False
        self.description_parts = []

        # Key-Value Pairs (Dates)
        self.in_kv_row = False
        self.kv_div_depth = 0
        self.in_key = False
        self.in_val = False
