        self.price_captured = False

        # Phone
        self.in_phone_container = False # general container .ad_phone
        self.in_cphone = False # specific valid number container .cphone
        self.temp_phone = None

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        classes = attrs_dict.get('class', '').split()

        # 1. Link
        if tag == 'link' and attrs_dict.get('rel') == 'canonical':
            self.data['link'] = attrs_dict.get('href')

        # 2. Cover URL
        if tag == 'img' and 'simple-gallery-main-item' in classes:
            if not self.data['cover_url']:
                src = attrs_dict.get('src')
                if src:
                    if src.startswith('//'):
                        self.data['cover_url'] = 'https:' + src
                    elif src.startswith('/'):
                        self.data['cover_url'] = 'https://neagent.by' + src
                    else:
                        self.data['cover_url'] = src

        # 3. Address
        if tag == 'div' and 'c-card__addr' in classes and not self.main_address_captured:
            self.in_addr_block = True
            self.addr_div_depth = 0 
            self.raw_address_parts = [] 
        elif self.in_addr_block and tag == 'div':
            self.addr_div_depth += 1

        # 3b. H1 Fallback
        if tag == 'h1':
            self.in_h1 = True

        # 4. Description
        if tag == 'div' and 'text-content' in classes:
            self.in_text_content = True
            self.desc_div_depth = 0
        elif self.in_text_content and tag == 'div':
            self.desc_div_depth += 1
            if 'collapsing_header' in classes:
                self.ignore_desc = True

        # 5. Key-Value Rows (Dates)
        if tag == 'div' and 'key-value-item' in classes:
            self.in_kv_row = True
            self.kv_div_depth = 0
            self.current_target_field = None
            self.temp_val_text = ""
        elif self.in_kv_row and tag == 'div':
            self.kv_div_depth += 1
            if 'key' in classes:
                self.in_key = True
                self.temp_key_text = ""
            elif 'value' in classes:
                self.in_val = True
                self.temp_val_text = ""

        # 6. Price
        if tag == 'span' and 'ann-contact__price' in classes and not self.price_captured:
            self.in_price = True

        # 7. Phone
        # Check for specific class 'cphone' which contains the real number
        if 'cphone' in classes:
            self.in_cphone = True
        # Fallback: check for 'ad_phone' container if we haven't found a cphone yet
        elif 'ad_phone' in classes:
            self.in_phone_container = True

    def handle_endtag(self, tag):
        # Address End
        if self.in_addr_block and tag == 'div':
            if self.addr_div_depth == 0:
                self.in_addr_block = False
                self.main_address_captured = True
            else:
                self.addr_div_depth -= 1

        # H1 End
        if self.in_h1 and tag == 'h1':
            self.in_h1 = False

        # Description End
        if self.in_text_content and tag == 'div':
            if self.desc_div_depth == 0:
                self.in_text_content = False
            else:
                self.desc_div_depth -= 1

        # Key-Value End
        if self.in_kv_row and tag == 'div':
            if self.in_key:
                self.in_key = False
                key_text = self.temp_key_text.lower()
                if "дата добавления" in key_text or "создано" in key_text:
                    if not self.creation_captured:
                        self.current_target_field = "creation_date"
                elif "обновлено" in key_text or "дата изменения" in key_text:
                    if not self.update_captured:
                        self.current_target_field = "last_update"

            elif self.in_val:
                self.in_val = False
                if self.current_target_field:
                    clean_val = self.temp_val_text.strip()
                    if clean_val:
                        self.data[self.current_target_field] = clean_val
                        if self.current_target_field == "creation_date":
                            self.creation_captured = True
                        elif self.current_target_field == "last_update":
                            self.update_captured = True

            if self.kv_div_depth == 0:
                self.in_kv_row = False
            else:
                self.kv_div_depth -= 1

        # Price End
        if self.in_price and tag == 'span':
            self.in_price = False
            self.price_captured = True

        # Phone End
        if self.in_cphone and tag == 'div':
            self.in_cphone = False
        if self.in_phone_container and tag == 'span': # ad_phone is a span
            self.in_phone_container = False

    def handle_data(self, data):
        content = data.strip()
        if not content:
            return

        # Address
        if self.in_addr_block:
            self.raw_address_parts.append(content)

        # H1
        if self.in_h1:
            self.h1_text += data

        # Description
        if self.in_text_content and not self.ignore_desc:
            self.description_parts.append(content)

        # KV Data
        if self.in_key:
            self.temp_key_text += data
        if self.in_val:
            self.temp_val_text += data

        # Price
        if self.in_price:
            self.data['price'] = content

        # Phone
        if self.in_cphone:
            # High priority: Found a cphone div, which usually contains the real number
            self.data['phone'] = content
        elif self.in_phone_container:
            # Low priority: inside ad_phone block. 
            # Only save if we don't have a phone yet, or if current phone is masked ("XX")
            is_masked = 'XX' in content
            current_phone = self.data.get('phone')

            if not current_phone:
                # Capture whatever we find if we have nothing
                self.data['phone'] = content
            elif 'XX' in current_phone and not is_masked:
                 # Upgrade from masked to unmasked if possible (unlikely in this order but safe)
                 self.data['phone'] = content

    def get_json(self):
        # 1. Process Address
        final_addr = ""
        if self.raw_address_parts:
            clean_parts = []
            for part in self.raw_address_parts:
                cleaned = part.strip(',. ')
                if cleaned and cleaned.lower() != 'минск':
                    clean_parts.append(cleaned)
            final_addr = ", ".join(clean_parts)

        # Fallback Address
        if not final_addr and self.h1_text:
            text = self.h1_text.strip()
            text = text.replace("Снять комнату в Минске,", "").replace("Снять комнату,", "").strip()
            text = re.sub(r'(,\s*)?[\d\s]+(бел\.?)?\s*руб.*$', '', text, flags=re.IGNORECASE)
            text = re.sub(r'по цене.*$', '', text, flags=re.IGNORECASE)
            final_addr = text.strip(', ')

        self.data['address'] = final_addr

        # 2. Process Description
        self.data['description'] = " ".join(self.description_parts).strip()

        return self.data

# --- Execution Block ---


